  ('heelevel3-c8735cdb-moex-00139', 'heelevel3-c8735cdb', 'heelevel3-c8735cdb-moex-112-3082b5f1', 'sub-heelevel3-c8735cdb-03', NULL, 'single_choice', '依據實務見解，納稅義務人因違反稅法規定而受罰鍰處分，惟納稅義務人於行政訴訟程序中死亡， 則罰鍰處分應如何處置？', '["因納稅義務人死亡，法律關係即告消滅，故無法執行該罰鍰處分", "由繼承人繼承被繼承人之義務人地位，並繳納罰鍰", "納稅義務人死亡後，法院應以欠缺當事人能力為由駁回訴訟", "由繼承人於被繼承人遺產範圍內代繳罰鍰"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:17+00:00", "source_pdf_sha1": "35e987219517", "answer_pdf_sha1": "d76f1552cd83", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "332", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "公平交易管理"}'::jsonb, NULL),
  ('heelevel3-c8735cdb-moex-00140', 'heelevel3-c8735cdb', 'heelevel3-c8735cdb-moex-112-3082b5f1', 'sub-heelevel3-c8735cdb-03', NULL, 'single_choice', '關於國家表演藝術中心在組織及任務上之特性，不包括下列何者？', '["負執行公共事務之任務", "具有獨立之法律人格", "以企業化之方式營運", "所屬人員均具公務人員身分"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:17+00:00", "source_pdf_sha1": "35e987219517", "answer_pdf_sha1": "d76f1552cd83", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "332", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "公平交易管理"}'::jsonb, NULL),
  ('heelevel3-c8735cdb-moex-00141', 'heelevel3-c8735cdb', 'heelevel3-c8735cdb-moex-112-3082b5f1', 'sub-heelevel3-c8735cdb-03', NULL, 'single_choice', '依地方制度法規定，中央主管機關針對直轄市政府所辦理自治事項之監督，下列敘述何者錯誤？', '["地方政府辦理自治事項得自為立法並執行而負其政策規劃及行政執行責任", "地方政府辦理自治事項有違憲法或法律規定時，仍得予以撤銷、變更、廢止或停止其執行", "直轄市政府辦理自治事項違法時，由中央主管機關報行政院予以撤銷、變更、廢止或停止其執行", "地方政府辦理自治事項若有違背憲法或法律之疑義時，於司法院解釋前，中央主管機關得先予 以撤銷之"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:17+00:00", "source_pdf_sha1": "35e987219517", "answer_pdf_sha1": "d76f1552cd83", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "332", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "公平交易管理"}'::jsonb, NULL),
  ('heelevel3-c8735cdb-moex-00142', 'heelevel3-c8735cdb', 'heelevel3-c8735cdb-moex-112-3082b5f1', 'sub-heelevel3-c8735cdb-03', NULL, 'single_choice', '關於機關權限之敘述，下列何者錯誤？', '["行政機關欲將部分權限委託不相隸屬之行政機關執行，係屬職權事項，故主管機關得依職權辦 理權限之委託", "行政機關將作成行政處分權限移轉予他機關時，則撤銷權之行使，應於權限移轉後改由承受其 業務機關為之", "行政處分無效事由之所謂「缺乏事務管轄權限」，應限縮於重大明顯之情事", "行政機關得依法規將部分權限委任相隸屬之行政機關執行"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:17+00:00", "source_pdf_sha1": "35e987219517", "answer_pdf_sha1": "d76f1552cd83", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "332", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "公平交易管理"}'::jsonb, NULL),
