  ('heelevel3-c8735cdb-moex-00145', 'heelevel3-c8735cdb', 'heelevel3-c8735cdb-moex-112-3082b5f1', 'sub-heelevel3-c8735cdb-03', NULL, 'single_choice', '關於公務員之懲戒程序，下列敘述何者錯誤？', '["懲戒案件係由懲戒法院設懲戒法庭，合議審理並裁判之", "公務員懲戒案件之審理制度係採一級一審", "應受懲戒行為，自行為終了之日起，至案件繫屬懲戒法院之日止，已逾10年者，不得予以休職 之懲戒", "公務員雖非執行職務，但其個人行為若致嚴重損害政府信譽，亦應受懲戒"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:17+00:00", "source_pdf_sha1": "35e987219517", "answer_pdf_sha1": "d76f1552cd83", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "332", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "公平交易管理"}'::jsonb, NULL),
